62	HRESULT DirectWriteResources::InitResources(const wstring& label_font_face,
63	                                            const int& label_font_point,
64	                                            const wstring& font_face,
65	                                            const int& font_point,
66	                                            const wstring& comment_font_face,
67	                                            const int& comment_font_point,
68	                                            const bool& vertical_text) {
69	  // prepare d2d1 resources
70	  DWRITE_WORD_WRAPPING wrapping =
71	      ((_style.max_width == 0 &&
72	        _style.layout_type != UIStyle::LAYOUT_VERTICAL_TEXT) ||
73	       (_style.max_height == 0 &&
74	        _style.layout_type == UIStyle::LAYOUT_VERTICAL_TEXT))
75	          ? DWRITE_WORD_WRAPPING_NO_WRAP
76	          : DWRITE_WORD_WRAPPING_WHOLE_WORD;
77	  DWRITE_WORD_WRAPPING wrapping_preedit =
78	      ((_style.max_width == 0 &&
79	        _style.layout_type != UIStyle::LAYOUT_VERTICAL_TEXT) ||
80	       (_style.max_height == 0 &&
81	        _style.layout_type == UIStyle::LAYOUT_VERTICAL_TEXT))
82	          ? DWRITE_WORD_WRAPPING_NO_WRAP
83	          : DWRITE_WORD_WRAPPING_CHARACTER;
84	  DWRITE_FLOW_DIRECTION flow = _style.vertical_text_left_to_right
85	                                   ? DWRITE_FLOW_DIRECTION_LEFT_TO_RIGHT
86	                                   : DWRITE_FLOW_DIRECTION_RIGHT_TO_LEFT;
87	
88	  // set main font a invalid font name, to make every font range customizable
89	  const wstring _mainFontFace = L"_InvalidFontName_";
90	  DWRITE_FONT_WEIGHT fontWeight = DWRITE_FONT_WEIGHT_NORMAL;
91	  DWRITE_FONT_STYLE fontStyle = DWRITE_FONT_STYLE_NORMAL;
92	  // convert percentage to float
93	  float linespacing = dpiScaleFontPoint * ((float)_style.linespacing / 100.0f);
94	  float baseline = dpiScaleFontPoint * ((float)_style.baseline / 100.0f);
95	  if (_style.layout_type == UIStyle::LAYOUT_VERTICAL_TEXT)
96	    baseline = linespacing / 2;
97	
98	  auto init_font = [&](const wstring& fontface, int fontpoint,
99	                       ComPtr<IDWriteTextFormat1>& _pTextFormat,
100	                       DWRITE_WORD_WRAPPING wrap) {
101	    vector<wstring> fontFaceStrVector;
102	    // text font text format set up
103	    fontFaceStrVector = ws_split(fontface, L",");
104	    // setup weight and style by the first unit of fontface setting string
105	    _ParseFontFace(fontface, fontWeight, fontStyle);
106	    fontFaceStrVector[0] =
107	        std::regex_replace(fontFaceStrVector[0],
108	                           std::wregex(STYLEORWEIGHT, std::wregex::icase), L"");
109	    // create text format with invalid font point will 'FAILED', no HR
110	    pDWFactory->CreateTextFormat(_mainFontFace.c_str(), NULL, fontWeight,
111	                                 fontStyle, DWRITE_FONT_STRETCH_NORMAL,
112	                                 fontpoint * dpiScaleFontPoint, L"",
113	                                 reinterpret_cast<IDWriteTextFormat**>(
114	                                     _pTextFormat.ReleaseAndGetAddressOf()));
115	    if (_pTextFormat != NULL) {
116	      if (vertical_text) {
117	        HR(_pTextFormat->SetFlowDirection(flow));
118	        HR(_pTextFormat->SetReadingDirection(
119	            DWRITE_READING_DIRECTION_TOP_TO_BOTTOM));
120	        HR(_pTextFormat->SetTextAlignment(DWRITE_TEXT_ALIGNMENT_LEADING));
121	      } else
122	        HR(_pTextFormat->SetTextAlignment(DWRITE_TEXT_ALIGNMENT_LEADING));
123	
124	      HR(_pTextFormat->SetParagraphAlignment(
125	          DWRITE_PARAGRAPH_ALIGNMENT_CENTER));
126	      HR(_pTextFormat->SetWordWrapping(wrapping));
127	      _SetFontFallback(_pTextFormat, fontFaceStrVector);
128	      if (_style.linespacing && _style.baseline)
129	        _pTextFormat->SetLineSpacing(DWRITE_LINE_SPACING_METHOD_UNIFORM,
130	                                     fontpoint * linespacing,
131	                                     fontpoint * baseline);
132	    }
133	    decltype(fontFaceStrVector)().swap(fontFaceStrVector);
134	  };
135	  init_font(font_face, font_point, pTextFormat, wrapping);
136	  init_font(font_face, font_point, pPreeditTextFormat, wrapping_preedit);
137	  init_font(label_font_face, label_font_point, pLabelTextFormat, wrapping);
138	  init_font(comment_font_face, comment_font_point, pCommentTextFormat,
139	            wrapping);
140	  return S_OK;
