223	static UINT GetValue(const wstring& wstr, const int fallback) {
224	  try {
225	    return std::stoul(wstr.c_str(), 0, 16);
226	  } catch (...) {
227	    return fallback;
228	  }
229	}
230	
231	void DirectWriteResources::_SetFontFallback(
232	    ComPtr<IDWriteTextFormat1>& textFormat,
233	    const vector<wstring>& fontVector) {
234	  ComPtr<IDWriteFontFallback> pSysFallback;
235	  HR(pDWFactory->GetSystemFontFallback(pSysFallback.ReleaseAndGetAddressOf()));
236	  ComPtr<IDWriteFontFallback> pFontFallback = NULL;
237	  ComPtr<IDWriteFontFallbackBuilder> pFontFallbackBuilder = NULL;
238	  HR(pDWFactory->CreateFontFallbackBuilder(
239	      pFontFallbackBuilder.ReleaseAndGetAddressOf()));
240	  vector<wstring> fallbackFontsVector;
241	  for (UINT32 i = 0; i < fontVector.size(); i++) {
242	    fallbackFontsVector = ws_split(fontVector[i], L":");
243	    wstring _fontFaceWstr, firstWstr, lastWstr;
244	    if (fallbackFontsVector.size() == 3) {
245	      _fontFaceWstr = fallbackFontsVector[0];
246	      firstWstr = fallbackFontsVector[1];
247	      lastWstr = fallbackFontsVector[2];
248	      if (lastWstr.empty())
249	        lastWstr = L"10ffff";
250	      if (firstWstr.empty())
251	        firstWstr = L"0";
252	    } else if (fallbackFontsVector.size() == 2)  // fontName : codepoint
253	    {
254	      _fontFaceWstr = fallbackFontsVector[0];
255	      firstWstr = fallbackFontsVector[1];
256	      if (firstWstr.empty())
257	        firstWstr = L"0";
258	      lastWstr = L"10ffff";
259	    } else if (fallbackFontsVector.size() ==
260	               1)  // if only font defined, use all range
261	    {
262	      _fontFaceWstr = fallbackFontsVector[0];
263	      firstWstr = L"0";
264	      lastWstr = L"10ffff";
265	    }
266	    UINT first = GetValue(firstWstr, 0), last = GetValue(lastWstr, 0x10ffff);
267	    DWRITE_UNICODE_RANGE range = {first, last};
268	    const WCHAR* familys = {_fontFaceWstr.c_str()};
269	    HR(pFontFallbackBuilder->AddMapping(&range, 1, &familys, 1));
270	    decltype(fallbackFontsVector)().swap(fallbackFontsVector);
271	  }
272	  // add system defalt font fallback
273	  HR(pFontFallbackBuilder->AddMappings(pSysFallback.Get()));
274	  HR(pFontFallbackBuilder->CreateFontFallback(
275	      pFontFallback.ReleaseAndGetAddressOf()));
276	  HR(textFormat->SetFontFallback(pFontFallback.Get()));
277	  decltype(fallbackFontsVector)().swap(fallbackFontsVector);
278	}
