307	void DoGaussianBlur(Gdiplus::Bitmap* img, float radiusX, float radiusY) {
308	  if (!img || (radiusX <= 0.0f && radiusY <= 0.0f))
309	    return;
310	
311	  const int w = img->GetWidth();
312	  const int h = img->GetHeight();
313	
314	  // Clamp radii to prevent excessive computation
315	  if (radiusX > w / 2.0f)
316	    radiusX = w / 2.0f;
317	  if (radiusY > h / 2.0f)
318	    radiusY = h / 2.0f;
319	
320	  // Use unique_ptr for automatic memory management
321	  std::unique_ptr<Gdiplus::Bitmap> temp(
322	      new Gdiplus::Bitmap(w, h, img->GetPixelFormat()));
323	
324	  Gdiplus::BitmapData bitmapData1;
325	  Gdiplus::BitmapData bitmapData2;
326	  Gdiplus::Rect rect(0, 0, w, h);
327	
328	  if (Gdiplus::Ok ==
329	          img->LockBits(
330	              &rect, Gdiplus::ImageLockModeRead | Gdiplus::ImageLockModeWrite,
331	              img->GetPixelFormat(), &bitmapData1) &&
332	      Gdiplus::Ok ==
333	          temp->LockBits(
334	              &rect, Gdiplus::ImageLockModeRead | Gdiplus::ImageLockModeWrite,
335	              temp->GetPixelFormat(), &bitmapData2)) {
336	    BYTE* src = static_cast<BYTE*>(bitmapData1.Scan0);
337	    BYTE* dst = static_cast<BYTE*>(bitmapData2.Scan0);
338	
339	    const int bpp = 4;
340	    const int stride = bitmapData1.Stride;
341	
342	    gaussBlur_4(src, dst, w, h, radiusX, radiusY, bpp, stride);
343	
344	    img->UnlockBits(&bitmapData1);
345	    temp->UnlockBits(&bitmapData2);
346	  }
347	}
