namespace weasel {
/* start image gauss blur functions from
 * https://github.com/kenjinote/DropShadow/  */
#define myround(x) (int)((x) + 0.5)

void boxesForGauss(double sigma, int* sizes, int n) {
  double wIdeal = sqrt((12 * sigma * sigma / n) + 1);
  int wl = (int)floor(wIdeal);
  if (wl % 2 == 0)
    --wl;

  const double wu = (double)wl + 2;

  const double mIdeal = (12 * sigma * sigma - n * (LONGLONG)wl * wl -
                         4 * (LONGLONG)n * wl - 3 * (LONGLONG)n) /
                        (-4 * (LONGLONG)wl - 4);
  const int m = myround(mIdeal);

  for (int i = 0; i < n; ++i)
    sizes[i] = int(i < m ? wl : wu);
}

void boxBlurH_4(BYTE* scl,
                BYTE* tcl,
                int w,
                int h,
                int r,
                int bpp,
                int stride) {
  float iarr = (float)(1. / ((LONGLONG)r + r + 1));
#pragma omp \
    parallel for if (h > 64)  // Parallelize for images taller than 64 pixels
  for (int i = 0; i < h; ++i) {
    int ti1 = i * stride;
    int ti2 = i * stride + 1;
    int ti3 = i * stride + 2;
    int ti4 = i * stride + 3;

    int li1 = ti1;
    int li2 = ti2;
    int li3 = ti3;
    int li4 = ti4;

    int ri1 = ti1 + r * bpp;
    int ri2 = ti2 + r * bpp;
    int ri3 = ti3 + r * bpp;
    int ri4 = ti4 + r * bpp;

    int fv1 = scl[ti1];
    int fv2 = scl[ti2];
    int fv3 = scl[ti3];
    int fv4 = scl[ti4];

    int lv1 = scl[ti1 + (w - 1) * bpp];
    int lv2 = scl[ti2 + (w - 1) * bpp];
    int lv3 = scl[ti3 + (w - 1) * bpp];
    int lv4 = scl[ti4 + (w - 1) * bpp];

    int val1 = (r + 1) * fv1;
    int val2 = (r + 1) * fv2;
    int val3 = (r + 1) * fv3;
    int val4 = (r + 1) * fv4;

    for (int j = 0; j < r; ++j) {
      val1 += scl[ti1 + j * bpp];
      val2 += scl[ti2 + j * bpp];
      val3 += scl[ti3 + j * bpp];
      val4 += scl[ti4 + j * bpp];
    }

    for (int j = 0; j <= r; ++j) {
      val1 += scl[ri1] - fv1;
      val2 += scl[ri2] - fv2;
      val3 += scl[ri3] - fv3;
      val4 += scl[ri4] - fv4;

      tcl[ti1] = myround(val1 * iarr);
      tcl[ti2] = myround(val2 * iarr);
      tcl[ti3] = myround(val3 * iarr);
      tcl[ti4] = myround(val4 * iarr);

      ri1 += bpp;
      ri2 += bpp;
      ri3 += bpp;
      ri4 += bpp;

      ti1 += bpp;
      ti2 += bpp;
      ti3 += bpp;
      ti4 += bpp;
    }

    for (int j = r + 1; j < w - r; ++j) {
      val1 += scl[ri1] - scl[li1];
      val2 += scl[ri2] - scl[li2];
      val3 += scl[ri3] - scl[li3];
      val4 += scl[ri4] - scl[li4];

      tcl[ti1] = myround(val1 * iarr);
      tcl[ti2] = myround(val2 * iarr);
      tcl[ti3] = myround(val3 * iarr);
      tcl[ti4] = myround(val4 * iarr);

      ri1 += bpp;
      ri2 += bpp;
      ri3 += bpp;
      ri4 += bpp;

      li1 += bpp;
      li2 += bpp;
      li3 += bpp;
      li4 += bpp;

      ti1 += bpp;
      ti2 += bpp;
      ti3 += bpp;
      ti4 += bpp;
    }

    for (int j = w - r; j < w; ++j) {
      val1 += lv1 - scl[li1];
      val2 += lv2 - scl[li2];
      val3 += lv3 - scl[li3];
      val4 += lv4 - scl[li4];

      tcl[ti1] = myround(val1 * iarr);
      tcl[ti2] = myround(val2 * iarr);
      tcl[ti3] = myround(val3 * iarr);
      tcl[ti4] = myround(val4 * iarr);

      li1 += bpp;
      li2 += bpp;
      li3 += bpp;
      li4 += bpp;

      ti1 += bpp;
      ti2 += bpp;
      ti3 += bpp;
      ti4 += bpp;
    }
  }
}

