    int val1 = (r + 1) * fv1;
    int val2 = (r + 1) * fv2;
    int val3 = (r + 1) * fv3;
    int val4 = (r + 1) * fv4;

    for (int j = 0; j < r; ++j) {
      val1 += scl[ti1 + j * stride];
      val2 += scl[ti2 + j * stride];
      val3 += scl[ti3 + j * stride];
      val4 += scl[ti4 + j * stride];
