135	void WeaselPanel::Refresh() {
136	  bool should_show_icon =
137	      (m_status.ascii_mode || !m_status.composing || !m_ctx.aux.empty());
138	  m_candidateCount = min(m_ctx.cinfo.candies.size(), MAX_CANDIDATES_COUNT);
139	  // When the candidate window changes from having content to having no content,
140	  // reset the sticky state
141	  if (m_lastCandidateCount > 0 && m_candidateCount == 0) {
142	    m_sticky = false;
143	  }
144	  m_lastCandidateCount = m_candidateCount;
145	  // check if to hide candidates window
146	  // show tips status, two kind of situation: 1) only aux strings, don't care
147	  // icon status; 2)only icon(ascii mode switching)
148	  bool show_tips =
149	      m_in_server &&
150	      ((!m_ctx.aux.empty() && m_ctx.cinfo.empty() && m_ctx.preedit.empty()) ||
151	       (m_ctx.empty() && should_show_icon));
152	  // show schema menu status: schema_id == L".default"
153	  bool show_schema_menu = m_status.schema_id == L".default";
154	  bool margin_negative =
155	      (DPI_SCALE(m_style.margin_x) < 0 || DPI_SCALE(m_style.margin_y) < 0);
156	  // when to hide_cadidates?
157	  // 1. margin_negative, and not in show tips mode( ascii switching / half-full
158	  // switching / simp-trad switching / error tips), and not in schema menu
159	  // 2. inline preedit without candidates
160	  bool inline_no_candidates =
161	      (m_style.inline_preedit && m_candidateCount == 0) && !show_tips;
162	  hide_candidates = inline_no_candidates ||
163	                    (margin_negative && !show_tips && !show_schema_menu);
164	
165	  // only RedrawWindow if no need to hide candidates window, or
166	  // inline_no_candidates
167	  if (!hide_candidates || inline_no_candidates) {
168	    _InitFontRes();
169	    _CreateLayout();
170	
171	    CDCHandle dc = GetDC();
172	    m_layout->DoLayout(dc, pDWR);
173	    ReleaseDC(dc);
174	    _ResizeWindow();
175	    _RepositionWindow();
176	    if (m_ctx != m_octx) {
177	      m_octx = m_ctx;
178	      RedrawWindow();
179	    }
180	  }
