202	static HBITMAP CopyDCToBitmap(HDC hDC, LPRECT lpRect) {
203	  if (!hDC || !lpRect || IsRectEmpty(lpRect))
204	    return NULL;
205	  HDC hMemDC = NULL;
206	  HBITMAP hBitmap = NULL, hOldBitmap = NULL;
207	  int nX, nY, nX2, nY2;
208	  int nWidth, nHeight;
209	
210	  nX = lpRect->left;
211	  nY = lpRect->top;
212	  nX2 = lpRect->right;
213	  nY2 = lpRect->bottom;
214	  nWidth = nX2 - nX;
215	  nHeight = nY2 - nY;
216	
217	  hMemDC = CreateCompatibleDC(hDC);
218	  if (!hMemDC)
219	    return NULL;
220	
221	  hBitmap = CreateCompatibleBitmap(hDC, nWidth, nHeight);
222	  if (!hBitmap) {
223	    DeleteDC(hMemDC);
224	    return NULL;
225	  }
226	
227	  hOldBitmap = (HBITMAP)SelectObject(hMemDC, hBitmap);
228	  if (!hOldBitmap) {
229	    DeleteObject(hBitmap);
230	    DeleteDC(hMemDC);
231	    return NULL;
232	  }
233	
234	  if (!BitBlt(hMemDC, 0, 0, nWidth, nHeight, hDC, nX, nY, SRCCOPY)) {
235	    // restore and cleanup
236	    SelectObject(hMemDC, hOldBitmap);
237	    DeleteObject(hBitmap);
238	    DeleteDC(hMemDC);
239	    return NULL;
240	  }
241	
242	  SelectObject(hMemDC, hOldBitmap);
243	  DeleteDC(hMemDC);
244	  return hBitmap;
245	}
246	
247	void WeaselPanel::_CaptureRect(CRect& rect) {
248	  HDC ScreenDC = ::GetDC(NULL);
249	  CRect rc;
250	  GetWindowRect(&rc);
251	  POINT WindowPosAtScreen = {rc.left, rc.top};
252	  CRect captureRect = rect;
253	  captureRect.OffsetRect(WindowPosAtScreen);
254	  // create bitmap first (avoid holding clipboard while capturing)
255	  HBITMAP bmp = CopyDCToBitmap(ScreenDC, LPRECT(captureRect));
256	  if (!bmp) {
257	    ::ReleaseDC(NULL, ScreenDC);
258	    return;
259	  }
260	
261	  // capture input window to clipboard
262	  if (!OpenClipboard()) {
263	    DEBUG << "_CaptureRect: OpenClipord ailed";
264	    DeleteObject(bmp);
265	    ::ReleaseDC(NULL, ScreenDC);
266	    return;
267	  }
268	  EmptyClipboard();
269	  if (!SetClipboardData(CF_BITMAP, bmp)) {
270	    DEBUG << "_CaptureRect: SetClipboardData failed";
271	    DeleteObject(bmp);
272	  }
273	  CloseClipboard();
274	  ::ReleaseDC(NULL, ScreenDC);
275	}
