335	
336	LRESULT WeaselPanel::OnLeftClickedDown(UINT uMsg,
337	                                       WPARAM wParam,
338	                                       LPARAM lParam,
339	                                       BOOL& bHandled) {
340	  if (hide_candidates) {
341	    bHandled = true;
342	    return 0;
343	  }
344	  CPoint point;
345	  point.x = GET_X_LPARAM(lParam);
346	  point.y = GET_Y_LPARAM(lParam);
347	
348	  // capture
349	  if (m_style.click_to_capture) {
350	    CRect recth = m_layout->GetCandidateRect((int)m_ctx.cinfo.highlighted);
351	    if (m_istorepos)
352	      recth.OffsetRect(0, m_offsetys[m_ctx.cinfo.highlighted]);
353	    recth.InflateRect(DPI_SCALE(m_style.hilite_padding_x),
354	                      DPI_SCALE(m_style.hilite_padding_y));
355	    // capture widow
356	    if (recth.PtInRect(point))
357	      _CaptureRect(recth);
358	    else {
359	      // if shadow_color transparent, decrease the capture rectangle size
360	      if (COLORTRANSPARENT(m_style.shadow_color) &&
361	          DPI_SCALE(m_style.shadow_radius) != 0) {
362	        CRect crc(rcw);
363	        int shadow_gap = (DPI_SCALE(m_style.shadow_offset_x) == 0 &&
364	                          DPI_SCALE(m_style.shadow_offset_y) == 0)
365	                             ? 2 * DPI_SCALE(m_style.shadow_radius)
366	                             : DPI_SCALE(m_style.shadow_radius) +
367	                                   DPI_SCALE(m_style.shadow_radius) / 2;
368	        int ofx = DPI_SCALE(m_style.hilite_padding_x) +
369	                              abs(DPI_SCALE(m_style.shadow_offset_x)) +
370	                              shadow_gap >
371	                          abs(DPI_SCALE(m_style.margin_x))
372	                      ? DPI_SCALE(m_style.hilite_padding_x) +
373	                            abs(DPI_SCALE(m_style.shadow_offset_x)) +
374	                            shadow_gap - abs(DPI_SCALE(m_style.margin_x))
375	                      : 0;
376	        int ofy = DPI_SCALE(m_style.hilite_padding_y) +
377	                              abs(DPI_SCALE(m_style.shadow_offset_y)) +
378	                              shadow_gap >
379	                          abs(DPI_SCALE(m_style.margin_y))
380	                      ? DPI_SCALE(m_style.hilite_padding_y) +
381	                            abs(DPI_SCALE(m_style.shadow_offset_y)) +
382	                            shadow_gap - abs(DPI_SCALE(m_style.margin_y))
383	                      : 0;
384	        crc.DeflateRect(m_layout->offsetX - ofx, m_layout->offsetY - ofy);
385	        _CaptureRect(crc);
386	      } else {
387	        _CaptureRect(rcw);
388	      }
389	    }
390	  }
391	  {
392	    if (!m_style.inline_preedit && m_candidateCount != 0 &&
393	        COLORNOTTRANSPARENT(m_style.prevpage_color) &&
394	        COLORNOTTRANSPARENT(m_style.nextpage_color)) {
395	      // click prepage
396	      if (m_ctx.cinfo.currentPage != 0) {
397	        CRect prc = m_layout->GetPrepageRect();
398	        if (m_istorepos)
399	          prc.OffsetRect(0, m_offsety_preedit);
400	        if (prc.PtInRect(point)) {
401	          bool nextPage = false;
402	          if (_UICallback)
403	            _UICallback(NULL, NULL, &nextPage, NULL);
404	          bHandled = true;
405	          return 0;
406	        }
407	      }
408	      // click nextpage
409	      if (!m_ctx.cinfo.is_last_page) {
410	        CRect prc = m_layout->GetNextpageRect();
411	        if (m_istorepos)
412	          prc.OffsetRect(0, m_offsety_preedit);
413	        if (prc.PtInRect(point)) {
414	          bool nextPage = true;
415	          if (_UICallback)
416	            _UICallback(NULL, NULL, &nextPage, NULL);
417	          bHandled = true;
418	          return 0;
419	        }
420	      }
421	    }
422	    // select by click relative actions
423	    for (size_t i = 0; i < m_candidateCount && i < MAX_CANDIDATES_COUNT; ++i) {
424	      CRect rect = m_layout->GetCandidateRect((int)i);
425	      if (m_istorepos)
426	        rect.OffsetRect(0, m_offsetys[i]);
427	      rect.InflateRect(DPI_SCALE(m_style.hilite_padding_x),
428	                       DPI_SCALE(m_style.hilite_padding_y));
429	      if (rect.PtInRect(point)) {
430	        bar_scale_ = 0.8f;
431	        // modify highlighted
432	        if (i != m_ctx.cinfo.highlighted) {
433	          if (_UICallback)
434	            _UICallback(NULL, &i, NULL, NULL);
435	        } else {
436	          RedrawWindow();
437	        }
438	        ptimer = UINT_PTR(this);
439	        ::SetTimer(m_hWnd, AUTOREV_TIMER, 1000, &WeaselPanel::OnTimer);
440	        bHandled = true;
441	        return 0;
442	      }
443	    }
444	  }
445	  bHandled = true;
446	  return 0;
447	}
