630	// draw preedit text, text only
631	bool WeaselPanel::_DrawPreedit(const Text& text,
632	                               CDCHandle dc,
633	                               const CRect& rc) {
634	  bool drawn = false;
635	  std::wstring const& t = text.str;
636	  IDWriteTextFormat1* txtFormat = pDWR->pPreeditTextFormat.Get();
637	
638	  if (!t.empty()) {
639	    weasel::TextRange range = m_layout->GetPreeditRange();
640	
641	    if (range.start < range.end) {
642	      std::wstring before_str = t.substr(0, range.start);
643	      std::wstring hilited_str = t.substr(range.start, range.end);
644	      std::wstring after_str = t.substr(range.end);
645	      CSize beforeSz = m_layout->GetBeforeSize();
646	      CSize hilitedSz = m_layout->GetHilitedSize();
647	      CSize afterSz = m_layout->GetAfterSize();
648	
649	      int x = rc.left;
650	      int y = rc.top;
651	
652	      if (range.start > 0) {
653	        // zzz
654	        std::wstring str_before(t.substr(0, range.start));
655	        CRect rc_before;
656	        if (m_style.layout_type == UIStyle::LAYOUT_VERTICAL_TEXT)
657	          rc_before = CRect(rc.left, y, rc.right, y + beforeSz.cy);
658	        else
659	          rc_before = CRect(x, rc.top, rc.left + beforeSz.cx, rc.bottom);
660	        _TextOut(rc_before, str_before.c_str(), str_before.length(),
661	                 m_style.text_color, txtFormat);
662	        if (m_style.layout_type == UIStyle::LAYOUT_VERTICAL_TEXT)
663	          y += beforeSz.cy + DPI_SCALE(m_style.hilite_spacing);
664	        else
665	          x += beforeSz.cx + DPI_SCALE(m_style.hilite_spacing);
666	      }
667	      {
668	        // zzz[yyy]
669	        std::wstring str_highlight(
670	            t.substr(range.start, (size_t)range.end - range.start));
671	        CRect rc_hi;
672	
673	        if (m_style.layout_type == UIStyle::LAYOUT_VERTICAL_TEXT)
674	          rc_hi = CRect(rc.left, y, rc.right, y + hilitedSz.cy);
675	        else
676	          rc_hi = CRect(x, rc.top, x + hilitedSz.cx, rc.bottom);
677	        _TextOut(rc_hi, str_highlight.c_str(), str_highlight.length(),
678	                 m_style.hilited_text_color, txtFormat);
679	        if (m_style.layout_type == UIStyle::LAYOUT_VERTICAL_TEXT)
680	          y += rc_hi.Height() + DPI_SCALE(m_style.hilite_spacing);
681	        else
682	          x += rc_hi.Width() + DPI_SCALE(m_style.hilite_spacing);
683	      }
684	      if (range.end < static_cast<int>(t.length())) {
685	        // zzz[yyy]xxx
686	        std::wstring str_after(t.substr(range.end));
687	        CRect rc_after;
688	        if (m_style.layout_type == UIStyle::LAYOUT_VERTICAL_TEXT)
689	          rc_after = CRect(rc.left, y, rc.right, y + afterSz.cy);
690	        else
691	          rc_after = CRect(x, rc.top, x + afterSz.cx, rc.bottom);
692	        _TextOut(rc_after, str_after.c_str(), str_after.length(),
693	                 m_style.text_color, txtFormat);
694	      }
695	    } else {
696	      CRect rcText(rc.left, rc.top, rc.right, rc.bottom);
697	      _TextOut(rcText, t.c_str(), t.length(), m_style.text_color, txtFormat);
698	    }
699	    // draw pager mark if not inline_preedit if necessary
700	    if (m_candidateCount && !m_style.inline_preedit &&
701	        COLORNOTTRANSPARENT(m_style.prevpage_color) &&
702	        COLORNOTTRANSPARENT(m_style.nextpage_color)) {
703	      const std::wstring pre = L"<";
704	      const std::wstring next = L">";
705	      CRect prc = m_layout->GetPrepageRect();
706	      // clickable color / disabled color
707	      int color =
708	          m_ctx.cinfo.currentPage ? m_style.prevpage_color : m_style.text_color;
709	      if (m_istorepos)
710	        prc.OffsetRect(0, m_offsety_preedit);
711	      _TextOut(prc, pre.c_str(), pre.length(), color, txtFormat);
712	
713	      CRect nrc = m_layout->GetNextpageRect();
714	      // clickable color / disabled color
715	      color = m_ctx.cinfo.is_last_page ? m_style.text_color
716	                                       : m_style.nextpage_color;
717	      if (m_istorepos)
718	        nrc.OffsetRect(0, m_offsety_preedit);
719	      _TextOut(nrc, next.c_str(), next.length(), color, txtFormat);
720	    }
721	    drawn = true;
722	  }
723	  return drawn;
724	}
