726	// draw hilited back color, back only
727	bool WeaselPanel::_DrawPreeditBack(const Text& text,
728	                                   CDCHandle dc,
729	                                   const CRect& rc) {
730	  bool drawn = false;
731	  std::wstring const& t = text.str;
732	  IDWriteTextFormat1* txtFormat = pDWR->pPreeditTextFormat.Get();
733	
734	  if (!t.empty()) {
735	    weasel::TextRange range = m_layout->GetPreeditRange();
736	
737	    if (range.start < range.end) {
738	      CSize beforeSz = m_layout->GetBeforeSize();
739	      CSize hilitedSz = m_layout->GetHilitedSize();
740	
741	      int x = rc.left;
742	      int y = rc.top;
743	
744	      if (range.start > 0) {
745	        if (m_style.layout_type == UIStyle::LAYOUT_VERTICAL_TEXT)
746	          y += beforeSz.cy + DPI_SCALE(m_style.hilite_spacing);
747	        else
748	          x += beforeSz.cx + DPI_SCALE(m_style.hilite_spacing);
749	      }
750	      {
751	        CRect rc_hi;
752	        if (m_style.layout_type == UIStyle::LAYOUT_VERTICAL_TEXT)
753	          rc_hi = CRect(rc.left, y, rc.right, y + hilitedSz.cy);
754	        else
755	          rc_hi = CRect(x, rc.top, x + hilitedSz.cx, rc.bottom);
756	        // if preedit rect size smaller than icon, fill the gap to
757	        // STATUS_ICON_SIZE
758	        if (m_layout->ShouldDisplayStatusIcon()) {
759	          if ((m_style.layout_type == UIStyle::LAYOUT_HORIZONTAL ||
760	               m_style.layout_type == UIStyle::LAYOUT_VERTICAL) &&
761	              hilitedSz.cy < STATUS_ICON_SIZE)
762	            rc_hi.InflateRect(0, (STATUS_ICON_SIZE - hilitedSz.cy) / 2);
763	          if (m_style.layout_type == UIStyle::LAYOUT_VERTICAL_TEXT &&
764	              hilitedSz.cx < STATUS_ICON_SIZE)
765	            rc_hi.InflateRect((STATUS_ICON_SIZE - hilitedSz.cx) / 2, 0);
766	        }
767	
768	        rc_hi.InflateRect(DPI_SCALE(m_style.hilite_padding_x),
769	                          DPI_SCALE(m_style.hilite_padding_y));
770	        IsToRoundStruct rd = m_layout->GetTextRoundInfo();
771	        if (m_istorepos) {
772	          std::swap(rd.IsTopLeftNeedToRound, rd.IsBottomLeftNeedToRound);
773	          std::swap(rd.IsTopRightNeedToRound, rd.IsBottomRightNeedToRound);
774	        }
775	        _HighlightText(dc, rc_hi, m_style.hilited_back_color,
776	                       m_style.hilited_shadow_color,
777	                       DPI_SCALE(m_style.round_corner), BackType::TEXT, rd);
778	      }
779	    }
780	    drawn = true;
781	  }
782	  return drawn;
783	}
