785	bool WeaselPanel::_DrawCandidates(CDCHandle& dc, bool back) {
786	  bool drawn = false;
787	  const std::vector<Text>& candidates(m_ctx.cinfo.candies);
788	  const std::vector<Text>& comments(m_ctx.cinfo.comments);
789	  const std::vector<Text>& labels(m_ctx.cinfo.labels);
790	  // prevent all text format nullptr
791	  if (pDWR->pTextFormat.Get() == nullptr &&
792	      pDWR->pLabelTextFormat.Get() == nullptr &&
793	      pDWR->pCommentTextFormat.Get() == nullptr) {
794	    _InitFontRes(true);
795	  }
796	  ComPtr<IDWriteTextFormat1> txtFormat = pDWR->pTextFormat;
797	  ComPtr<IDWriteTextFormat1> labeltxtFormat = pDWR->pLabelTextFormat;
798	  ComPtr<IDWriteTextFormat1> commenttxtFormat = pDWR->pCommentTextFormat;
799	  BackType bkType = BackType::CAND;
800	
801	  CRect rect;
802	  // draw back color and shadow color, with gdi+
803	  if (back) {
804	    // if candidate_shadow_color not transparent, draw candidate shadow first
805	    if (COLORNOTTRANSPARENT(m_style.candidate_shadow_color)) {
806	      for (auto i = 0; i < m_candidateCount && i < MAX_CANDIDATES_COUNT; ++i) {
807	        if (i == m_ctx.cinfo.highlighted || i == m_hoverIndex)
808	          continue;  // draw non hilited candidates only
809	        rect = m_layout->GetCandidateRect((int)i);
810	        IsToRoundStruct rd = m_layout->GetRoundInfo(i);
811	        if (m_istorepos) {
812	          rect.OffsetRect(0, m_offsetys[i]);
813	          ReconfigRoundInfo(rd, i, m_candidateCount);
814	        }
815	        rect.InflateRect(DPI_SCALE(m_style.hilite_padding_x),
816	                         DPI_SCALE(m_style.hilite_padding_y));
817	        _HighlightText(dc, rect, 0x00000000, m_style.candidate_shadow_color,
818	                       DPI_SCALE(m_style.round_corner), bkType, rd);
819	        drawn = true;
820	      }
821	    }
822	    // draw non highlighted candidates, without shadow
823	    if ((COLORNOTTRANSPARENT(m_style.candidate_back_color) ||
824	         COLORNOTTRANSPARENT(m_style.candidate_border_color))) {
825	      for (auto i = 0; i < m_candidateCount && i < MAX_CANDIDATES_COUNT; ++i) {
826	        if (i == m_ctx.cinfo.highlighted || i == m_hoverIndex)
827	          continue;
828	        rect = m_layout->GetCandidateRect((int)i);
829	        IsToRoundStruct rd = m_layout->GetRoundInfo(i);
830	        if (m_istorepos) {
831	          rect.OffsetRect(0, m_offsetys[i]);
832	          ReconfigRoundInfo(rd, i, m_candidateCount);
833	        }
834	        rect.InflateRect(DPI_SCALE(m_style.hilite_padding_x),
835	                         DPI_SCALE(m_style.hilite_padding_y));
836	        _HighlightText(dc, rect, m_style.candidate_back_color, 0x00000000,
837	                       DPI_SCALE(m_style.round_corner), bkType, rd,
838	                       m_style.candidate_border_color);
839	        drawn = true;
840	      }
841	    }
842	    // draw semi-hilite background and shadow
843	    if (m_hoverIndex >= 0) {
844	      rect = m_layout->GetCandidateRect(m_hoverIndex);
845	      IsToRoundStruct rd = m_layout->GetRoundInfo(m_hoverIndex);
846	      if (m_istorepos) {
847	        rect.OffsetRect(0, m_offsetys[m_hoverIndex]);
848	        ReconfigRoundInfo(rd, m_hoverIndex, m_candidateCount);
849	      }
850	      rect.InflateRect(DPI_SCALE(m_style.hilite_padding_x),
851	                       DPI_SCALE(m_style.hilite_padding_y));
852	      _HighlightText(dc, rect,
853	                     HALF_ALPHA_COLOR(m_style.hilited_candidate_back_color),
854	                     HALF_ALPHA_COLOR(m_style.hilited_candidate_shadow_color),
855	                     DPI_SCALE(m_style.round_corner), bkType, rd,
856	                     HALF_ALPHA_COLOR(m_style.hilited_candidate_border_color));
857	    }
858	    // draw highlighted background and shadow
859	    {
860	      rect = m_layout->GetHighlightRect();
861	      bool markSt = bar_scale_ == 1.0 || (!m_style.mark_text.empty());
862	      IsToRoundStruct rd = m_layout->GetRoundInfo(m_ctx.cinfo.highlighted);
863	      if (m_istorepos) {
864	        rect.OffsetRect(0, m_offsetys[m_ctx.cinfo.highlighted]);
865	        ReconfigRoundInfo(rd, m_ctx.cinfo.highlighted, m_candidateCount);
866	      }
867	      rect.InflateRect(DPI_SCALE(m_style.hilite_padding_x),
868	                       DPI_SCALE(m_style.hilite_padding_y));
869	      _HighlightText(dc, rect, m_style.hilited_candidate_back_color,
870	                     markSt ? m_style.hilited_candidate_shadow_color : 0,
871	                     DPI_SCALE(m_style.round_corner), bkType, rd,
872	                     m_style.hilited_candidate_border_color);
873	      if (m_style.mark_text.empty() &&
874	          COLORNOTTRANSPARENT(m_style.hilited_mark_color)) {
875	        int height =
876	            min(rect.Height() - DPI_SCALE(m_style.hilite_padding_y) * 2,
877	                rect.Height() - DPI_SCALE(m_style.round_corner) * 2);
878	        int width = min(rect.Width() - DPI_SCALE(m_style.hilite_padding_x) * 2,
879	                        rect.Width() - DPI_SCALE(m_style.round_corner) * 2);
880	        width = min(width, static_cast<int>(rect.Width() * 0.618));
881	        height = min(height, static_cast<int>(rect.Height() * 0.618));
882	        if (bar_scale_ != 1.0f) {
883	          width = static_cast<int>(width * bar_scale_);
884	          height = static_cast<int>(height * bar_scale_);
885	        }
886	        Gdiplus::Graphics g_back(dc);
887	        g_back.SetSmoothingMode(
888	            Gdiplus::SmoothingMode::SmoothingModeHighQuality);
889	        Gdiplus::Color mark_color =
890	            GDPCOLOR_FROM_COLORREF(m_style.hilited_mark_color);
891	        Gdiplus::SolidBrush mk_brush(mark_color);
892	        if (m_style.layout_type == UIStyle::LAYOUT_VERTICAL_TEXT) {
893	          int x = rect.left + (rect.Width() - width) / 2;
894	          CRect mkrc{x, rect.top, x + width, rect.top + m_layout->mark_height};
895	          GraphicsRoundRectPath mk_path(mkrc, mkrc.Height() / 2);
896	          g_back.FillPath(&mk_brush, &mk_path);
897	        } else {
898	          int y = rect.top + (rect.Height() - height) / 2;
899	          CRect mkrc{rect.left, y, rect.left + m_layout->mark_width,
900	                     y + height};
901	          GraphicsRoundRectPath mk_path(mkrc, mkrc.Width() / 2);
902	          g_back.FillPath(&mk_brush, &mk_path);
903	        }
904	      }
905	      drawn = true;
906	    }
907	  }
908	  // draw text with direct write
909	  else {
910	    // begin draw candidate texts
911	    int label_text_color, candidate_text_color, comment_text_color;
912	    for (auto i = 0; i < m_candidateCount && i < MAX_CANDIDATES_COUNT; ++i) {
913	      if (i == m_ctx.cinfo.highlighted || i == m_hoverIndex) {
914	        label_text_color = m_style.hilited_label_text_color;
915	        candidate_text_color = m_style.hilited_candidate_text_color;
916	        comment_text_color = m_style.hilited_comment_text_color;
917	      } else {
918	        label_text_color = m_style.label_text_color;
919	        candidate_text_color = m_style.candidate_text_color;
920	        comment_text_color = m_style.comment_text_color;
921	      }
922	      // Draw label
923	      std::wstring label = m_layout->GetLabelText(
924	          labels, (int)i, m_style.label_text_format.c_str());
925	      if (!label.empty()) {
926	        rect = m_layout->GetCandidateLabelRect((int)i);
927	        if (m_istorepos)
928	          rect.OffsetRect(0, m_offsetys[i]);
929	        _TextOut(rect, label.c_str(), label.length(), label_text_color,
930	                 labeltxtFormat.Get());
931	      }
932	      // Draw text
933	      std::wstring text = candidates.at(i).str;
934	      if (!text.empty()) {
935	        rect = m_layout->GetCandidateTextRect((int)i);
936	        if (m_istorepos)
937	          rect.OffsetRect(0, m_offsetys[i]);
938	        _TextOut(rect, text.c_str(), text.length(), candidate_text_color,
939	                 txtFormat.Get());
940	      }
941	      // Draw comment
942	      std::wstring comment = comments.at(i).str;
943	      if (!comment.empty() && COLORNOTTRANSPARENT(comment_text_color)) {
944	        rect = m_layout->GetCandidateCommentRect((int)i);
945	        if (m_istorepos)
946	          rect.OffsetRect(0, m_offsetys[i]);
947	        _TextOut(rect, comment.c_str(), comment.length(), comment_text_color,
948	                 commenttxtFormat.Get());
949	      }
950	      drawn = true;
951	    }
952	    // draw highlight mark
953	    {
954	      if (!m_style.mark_text.empty() &&
955	          COLORNOTTRANSPARENT(m_style.hilited_mark_color)) {
956	        CRect rc = m_layout->GetHighlightRect();
957	        if (m_istorepos)
958	          rc.OffsetRect(0, m_offsetys[m_ctx.cinfo.highlighted]);
959	        rc.InflateRect(DPI_SCALE(m_style.hilite_padding_x),
960	                       DPI_SCALE(m_style.hilite_padding_y));
961	        int vgap = m_layout->mark_height
962	                       ? (rc.Height() - m_layout->mark_height) / 2
963	                       : 0;
964	        int hgap =
965	            m_layout->mark_width ? (rc.Width() - m_layout->mark_width) / 2 : 0;
966	        CRect hlRc;
967	        if (m_style.layout_type == UIStyle::LAYOUT_VERTICAL_TEXT)
968	          hlRc = CRect(rc.left + hgap,
969	                       rc.top + DPI_SCALE(m_style.hilite_padding_y),
970	                       rc.left + hgap + m_layout->mark_width,
971	                       rc.top + DPI_SCALE(m_style.hilite_padding_y) +
972	                           m_layout->mark_height);
973	        else
974	          hlRc = CRect(rc.left + DPI_SCALE(m_style.hilite_padding_x),
975	                       rc.top + vgap,
976	                       rc.left + DPI_SCALE(m_style.hilite_padding_x) +
977	                           m_layout->mark_width,
978	                       rc.bottom - vgap);
979	        _TextOut(hlRc, m_style.mark_text.c_str(), m_style.mark_text.length(),
980	                 m_style.hilited_mark_color, pDWR->pTextFormat.Get());
981	      }
982	    }
983	  }
984	  return drawn;
985	}
