987	// draw client area
988	void WeaselPanel::DoPaint(CDCHandle dc) {
989	  // turn off WS_EX_TRANSPARENT, for better resp performance
990	  ModifyStyleEx(WS_EX_TRANSPARENT, WS_EX_LAYERED);
991	  GetClientRect(&rcw);
992	  // prepare memDC
993	  CDCHandle hdc = ::GetDC(m_hWnd);
994	  CDCHandle memDC = ::CreateCompatibleDC(hdc);
995	  HBITMAP memBitmap = ::CreateCompatibleBitmap(hdc, rcw.Width(), rcw.Height());
996	  ::SelectObject(memDC, memBitmap);
997	  ReleaseDC(hdc);
998	  bool drawn = false;
999	  if (!hide_candidates) {
1000	    CRect auxrc = m_layout->GetAuxiliaryRect();
1001	    CRect preeditrc = m_layout->GetPreeditRect();
1002	    if (m_istorepos) {
1003	      CRect* rects = new CRect[m_candidateCount];
1004	      int* btmys = new int[m_candidateCount];
1005	      for (auto i = 0; i < m_candidateCount && i < MAX_CANDIDATES_COUNT; ++i) {
1006	        rects[i] = m_layout->GetCandidateRect(i);
1007	        btmys[i] = rects[i].bottom;
1008	      }
1009	      if (m_candidateCount) {
1010	        if (!m_layout->IsInlinePreedit() && !m_ctx.preedit.str.empty())
1011	          m_offsety_preedit =
1012	              rects[m_candidateCount - 1].bottom - preeditrc.bottom;
1013	        if (!m_ctx.aux.str.empty())
1014	          m_offsety_aux = rects[m_candidateCount - 1].bottom - auxrc.bottom;
1015	      } else {
1016	        m_offsety_preedit = 0;
1017	        m_offsety_aux = 0;
1018	      }
1019	      int base_gap = 0;
1020	      if (!m_ctx.aux.str.empty())
1021	        base_gap = auxrc.Height() + m_style.spacing;
1022	      else if (!m_layout->IsInlinePreedit() && !m_ctx.preedit.str.empty())
1023	        base_gap = preeditrc.Height() + m_style.spacing;
1024	
1025	      for (auto i = 0; i < m_candidateCount && i < MAX_CANDIDATES_COUNT; ++i) {
1026	        if (i == 0)
1027	          m_offsetys[i] =
1028	              btmys[m_candidateCount - i - 1] - base_gap - rects[i].bottom;
1029	        else
1030	          m_offsetys[i] = (rects[i - 1].top + m_offsetys[i - 1] -
1031	                           DPI_SCALE(m_style.candidate_spacing)) -
1032	                          rects[i].bottom;
1033	      }
1034	      delete[] rects;
1035	      delete[] btmys;
1036	    }
1037	    // background and candidates back, hilite back drawing start
1038	    if ((!m_ctx.empty() && !m_style.inline_preedit) ||
1039	        (m_style.inline_preedit && (m_candidateCount || !m_ctx.aux.empty()))) {
1040	      CRect backrc = m_layout->GetContentRect();
1041	      _HighlightText(memDC, backrc, m_style.back_color, m_style.shadow_color,
1042	                     DPI_SCALE(m_style.round_corner_ex), BackType::BACKGROUND,
1043	                     IsToRoundStruct(), m_style.border_color);
1044	    }
1045	    if (!m_ctx.aux.str.empty()) {
1046	      if (m_istorepos)
1047	        auxrc.OffsetRect(0, m_offsety_aux);
1048	      drawn |= _DrawPreeditBack(m_ctx.aux, memDC, auxrc);
1049	    }
1050	    if (!m_layout->IsInlinePreedit() && !m_ctx.preedit.str.empty()) {
1051	      if (m_istorepos)
1052	        preeditrc.OffsetRect(0, m_offsety_preedit);
1053	      drawn |= _DrawPreeditBack(m_ctx.preedit, memDC, preeditrc);
1054	    }
1055	    if (m_candidateCount)
1056	      drawn |= _DrawCandidates(memDC, true);
1057	    // background and candidates back, hilite back drawing end
1058	
1059	    // begin  texts drawing, if pRenderTarget failed, force to reinit
1060	    // directwrite resources
1061	    if (FAILED(pDWR->pRenderTarget->BindDC(memDC, &rcw))) {
1062	      _InitFontRes(true);
1063	      pDWR->pRenderTarget->BindDC(memDC, &rcw);
1064	    }
1065	    pDWR->pRenderTarget->BeginDraw();
1066	    // draw auxiliary string
1067	    if (!m_ctx.aux.str.empty())
1068	      drawn |= _DrawPreedit(m_ctx.aux, memDC, auxrc);
1069	    // draw preedit string
1070	    if (!m_layout->IsInlinePreedit() && !m_ctx.preedit.str.empty())
1071	      drawn |= _DrawPreedit(m_ctx.preedit, memDC, preeditrc);
1072	    // draw candidates string
1073	    if (m_candidateCount)
1074	      drawn |= _DrawCandidates(memDC);
1075	    if (FAILED(pDWR->pRenderTarget->EndDraw())) {
1076	      _InitFontRes(true);
1077	      Refresh();
1078	    }
1079	    // end texts drawing
1080	
1081	    // status icon (I guess Metro IME stole my idea :)
1082	    if (m_layout->ShouldDisplayStatusIcon()) {
1083	      // decide if custom schema zhung icon to show
1084	      LoadIconNecessary(m_current_zhung_icon, m_style.current_zhung_icon,
1085	                        m_iconEnabled, IDI_ZH);
1086	      LoadIconNecessary(m_current_ascii_icon, m_style.current_ascii_icon,
1087	                        m_iconAlpha, IDI_EN);
1088	      LoadIconNecessary(m_current_half_icon, m_style.current_half_icon,
1089	                        m_iconHalf, IDI_HALF_SHAPE);
1090	      LoadIconNecessary(m_current_full_icon, m_style.current_full_icon,
1091	                        m_iconFull, IDI_FULL_SHAPE);
1092	      CRect iconRect(m_layout->GetStatusIconRect());
1093	      if (m_istorepos && !m_ctx.aux.str.empty())
1094	        iconRect.OffsetRect(0, m_offsety_aux);
1095	      else if (m_istorepos && !m_layout->IsInlinePreedit() &&
1096	               !m_ctx.preedit.str.empty())
1097	        iconRect.OffsetRect(0, m_offsety_preedit);
1098	
1099	      CIcon& icon(
1100	          m_status.disabled ? m_iconDisabled
1101	          : m_status.ascii_mode
1102	              ? m_iconAlpha
1103	              : (m_status.type == SCHEMA
1104	                     ? m_iconEnabled
1105	                     : (m_status.full_shape ? m_iconFull : m_iconHalf)));
1106	      memDC.DrawIconEx(iconRect.left, iconRect.top, icon, 0, 0);
1107	      drawn = true;
1108	    }
1109	    /* Nothing drawn, hide candidate window */
1110	    if (!drawn)
1111	      ShowWindow(SW_HIDE);
1112	  }
1113	  _LayerUpdate(rcw, memDC);
1114	
1115	  // clean objs
1116	  ::DeleteDC(memDC);
1117	  ::DeleteObject(memBitmap);
1118	}
