1222	void WeaselPanel::_RepositionWindow(const bool& adj) {
1223	  RECT rcWorkArea;
1224	  memset(&rcWorkArea, 0, sizeof(rcWorkArea));
1225	  HMONITOR hMonitor = MonitorFromRect(m_inputPos, MONITOR_DEFAULTTONEAREST);
1226	  if (hMonitor) {
1227	    MONITORINFO info;
1228	    info.cbSize = sizeof(MONITORINFO);
1229	    if (GetMonitorInfo(hMonitor, &info)) {
1230	      rcWorkArea = info.rcWork;
1231	    }
1232	    if (hMonitor != m_hMonitor) {
1233	      m_hMonitor = hMonitor;
1234	      m_redraw_by_monitor_change = true;
1235	    }
1236	  }
1237	  RECT rcWindow;
1238	  GetWindowRect(&rcWindow);
1239	  int width = (rcWindow.right - rcWindow.left);
1240	  int height = (rcWindow.bottom - rcWindow.top);
1241	  // keep panel visible
1242	  rcWorkArea.right -= width;
1243	  rcWorkArea.bottom -= height;
1244	  int x = m_inputPos.left;
1245	  int y = m_inputPos.bottom;
1246	  if (DPI_SCALE(m_style.shadow_radius)) {
1247	    x -= (DPI_SCALE(m_style.shadow_offset_x) >= 0 ||
1248	          COLORTRANSPARENT(m_style.shadow_color))
1249	             ? m_layout->offsetX
1250	             : (m_layout->offsetX / 2);
1251	    if (adj)
1252	      y -= (DPI_SCALE(m_style.shadow_offset_y) > 0 ||
1253	            COLORTRANSPARENT(m_style.shadow_color))
1254	               ? m_layout->offsetY
1255	               : (m_layout->offsetY / 2);
1256	  }
1257	  // for vertical text layout, flow right to left, make window left side
1258	  if (m_style.layout_type == UIStyle::LAYOUT_VERTICAL_TEXT &&
1259	      !m_style.vertical_text_left_to_right) {
1260	    x += m_layout->offsetX - width;
1261	    if (DPI_SCALE(m_style.shadow_offset_x) < 0)
1262	      x += m_layout->offsetX;
1263	  }
1264	  if (adj)
1265	    m_istorepos = false;
1266	  if (x > rcWorkArea.right)
1267	    x = rcWorkArea.right;  // over workarea right
1268	  if (x < rcWorkArea.left)
1269	    x = rcWorkArea.left;  // over workarea left
1270	  // show panel above the input focus if we're around the bottom
1271	  if (y > rcWorkArea.bottom || m_sticky) {
1272	    if (!m_sticky)
1273	      m_sticky = true;
1274	    y = m_inputPos.top - height - 6;  // over workarea bottom
1275	    if (DPI_SCALE(m_style.shadow_radius) &&
1276	        DPI_SCALE(m_style.shadow_offset_y) > 0)
1277	      y -= DPI_SCALE(m_style.shadow_offset_y);
1278	    m_istorepos = (m_style.vertical_auto_reverse &&
1279	                   m_style.layout_type == UIStyle::LAYOUT_VERTICAL);
1280	    if (DPI_SCALE(m_style.shadow_radius) > 0)
1281	      y += (DPI_SCALE(m_style.shadow_offset_y) < 0 ||
1282	            COLORTRANSPARENT(m_style.shadow_color))
1283	               ? m_layout->offsetY
1284	               : (m_layout->offsetY / 2);
1285	  }
1286	  if (y < rcWorkArea.top)
1287	    y = rcWorkArea.top;  // over workarea top
1288	  // memorize adjusted position (to avoid window bouncing on height change)
1289	  m_inputPos.bottom = y;
1290	  SetWindowPos(HWND_TOPMOST, x, y, 0, 0,
1291	               SWP_NOSIZE | SWP_NOACTIVATE | SWP_NOREDRAW);
1292	}
