937	// Blend foreground and background ARGB colors taking alpha into account.
938	// Returns an ABGR COLORREF with premultiplied alpha blended result.
939	static inline COLORREF blend_colors(COLORREF fcolor, COLORREF bcolor) {
940	  // Extract ARGB channels from both colors.
941	  BYTE fA = (fcolor >> 24) & 0xFF;
942	  BYTE fB = (fcolor >> 16) & 0xFF;
943	  BYTE fG = (fcolor >> 8) & 0xFF;
944	  BYTE fR = fcolor & 0xFF;
945	  BYTE bA = (bcolor >> 24) & 0xFF;
946	  BYTE bB = (bcolor >> 16) & 0xFF;
947	  BYTE bG = (bcolor >> 8) & 0xFF;
948	  BYTE bR = bcolor & 0xFF;
949	  // Convert alpha to [0,1]
950	  float fAlpha = fA / 255.0f;
951	  float bAlpha = bA / 255.0f;
952	  // Result alpha
953	  float retAlpha = fAlpha + (1 - fAlpha) * bAlpha;
954	  if (retAlpha <= 1e-6f) {
955	    // Fully transparent result — return background unchanged as fallback.
956	    return bcolor;
957	  }
958	  auto mix = [&](float fc, float bc) -> BYTE {
959	    return static_cast<BYTE>((fc * fAlpha + bc * bAlpha * (1 - fAlpha)) /
960	                             retAlpha);
961	  };
962	  BYTE retR = mix(fR, bR);
963	  BYTE retG = mix(fG, bG);
964	  BYTE retB = mix(fB, bB);
965	  BYTE outA = static_cast<BYTE>(retAlpha * 255.0f);
966	  return (static_cast<COLORREF>(outA) << 24) | (retB << 16) | (retG << 8) |
967	         retR;
968	}
969	// parse color value, with fallback value
970	static Bool _RimeGetColor(RimeConfig* config,
971	                          const std::string& key,
972	                          int& value,
973	                          const ColorFormat& fmt,
974	                          const unsigned int& fallback) {
975	  char color[256] = {0};
976	  if (!rime_api->config_get_string(config, key.c_str(), color, 256)) {
977	    value = fallback;
978	    return False;
979	  }
980	  const auto color_str = std::string(color);
981	  // adjudge if str is 0x 0X # hex color format, return trimmed hex part
